"""
Christ Layer — Ezra chapters 1–3
Run: python3 scripts/zc-christ-ezra-1-3.py

Key christological content:
- Ch 1: Cyrus as the anointed (Isa 45:1 = māšîaḥ) — the Gentile type of the true Anointed;
  Matt 28:18 surpasses Cyrus's claim; vessel-return = restoration of all that was stolen
- Ch 2 (70 verses): Every returning family is part of the named, counted remnant (Rom 11:5);
  Zerubbabel in Matthew's genealogy; priestly families as types of the royal priesthood
  (Rev 1:6); Nethinim inclusion prefigures Gentile ingrafting; genealogical crisis resolved
  only by a future priest (v63) = Christ who resolves all identity questions
- Ch 3: Altar before temple = cross before church; Feast of Tabernacles = John 1:14;
  the daily burnt offering = Christ's once-for-all offering (Heb 10:12-14);
  the foundation with singing = Christ as cornerstone (1 Pet 2:6); mixed joy/weeping =
  the "already but not yet" tension of Christ's inaugurated kingdom
"""

import json, pathlib

ROOT = pathlib.Path(__file__).parent.parent

def load_comm(source, book):
    p = ROOT / 'data' / 'commentary' / source / f'{book}.json'
    if p.exists():
        return json.loads(p.read_text())
    return {}

def save_comm(source, book, data):
    p = ROOT / 'data' / 'commentary' / source / f'{book}.json'
    p.parent.mkdir(parents=True, exist_ok=True)
    p.write_text(json.dumps(data, ensure_ascii=False, indent=None))
    print(f'  wrote {p.relative_to(ROOT)}')

def merge_comm(existing, new_data):
    for ch, verses in new_data.items():
        if ch not in existing:
            existing[ch] = {}
        for v, html in verses.items():
            if v not in existing[ch]:
                existing[ch][v] = html

EZRA_CHRIST_1_3 = {
  "1": {
    "1": "<p><em>Direct.</em> &ldquo;YHWH stirred up the spirit of Cyrus king of Persia.&rdquo; Isaiah had named Cyrus by name over 150 years before this moment (Isa 44:28; 45:1) and called him YHWH&rsquo;s <em>māšîaḥ</em> — the very title &ldquo;anointed one&rdquo; that identifies the Messiah. A Gentile king bears the Messiah&rsquo;s title as a type of the true Anointed One to come. Christ is the fulfillment that Cyrus only foreshadowed: Cyrus liberated an earthly people from an earthly captivity; Christ liberates humanity from the captivity of sin and death (Luke 4:18-19, citing Isa 61:1, the passage that follows the Cyrus oracles). The divine stirring of Cyrus&rsquo;s spirit anticipates the supreme divine act of stirring — the raising of Christ from the dead by the Spirit (Rom 8:11).</p>",
    "2": "<p><em>Theme.</em> Cyrus claims: &ldquo;YHWH the God of heaven has given me all the kingdoms of the earth.&rdquo; Christ&rsquo;s post-resurrection declaration surpasses this: &ldquo;All authority in heaven and on earth has been given to me&rdquo; (Matt 28:18). Cyrus received earthly kingdoms; Christ received authority over heaven and earth — the full cosmic scope that Cyrus&rsquo;s claim anticipated but could not embody. The escalation from &ldquo;kingdoms of the earth&rdquo; to &ldquo;authority in heaven and on earth&rdquo; marks the difference between type and fulfillment.</p>",
    "3": "<p><em>Theme.</em> &ldquo;Let him go up to Jerusalem&rdquo; — the invitation to ascend to the holy city to build the house of God. Christ&rsquo;s whole ministry was oriented toward the journey to Jerusalem (Luke 9:51: &ldquo;he set his face toward Jerusalem&rdquo;). He &ldquo;went up&rdquo; to Jerusalem for Passover (John 2:13; 5:1; 12:20), knowing he was going to build the true temple through his death and resurrection. His final ascension from Jerusalem (Acts 1:9) was the ultimate &ldquo;going up&rdquo; — to the Father&rsquo;s presence where he dwells as the completed temple.</p>",
    "4": "<p><em>Theme.</em> &ldquo;Let each survivor be assisted by the men of his place with silver and gold, with goods and with beasts.&rdquo; The Gentile support for the returning Jewish community prefigures the Gentile participation in the new covenant community. Paul describes the Gentile churches supporting the poor Jewish believers in Jerusalem as a participation in Israel&rsquo;s spiritual heritage (Rom 15:27). In Revelation&rsquo;s vision, &ldquo;the kings of the earth will bring their glory into&rdquo; the new Jerusalem (Rev 21:24) — the ultimate fulfillment of Gentile nations contributing their resources to YHWH&rsquo;s dwelling.</p>",
    "5": "<p><em>Theme.</em> The Spirit stirs the heads of fathers&rsquo; houses, the priests and Levites, and &ldquo;everyone whose spirit God had stirred.&rdquo; The divine stirring (<em>hēʿîr</em>) of individual people to undertake the return anticipates Pentecost: the Holy Spirit&rsquo;s arrival in Acts 2 stirs up a larger community to build the new temple — not of stone but of living people (1 Cor 3:16; Eph 2:21-22). Each person whose spirit is stirred is a foreshadowing of those whom the Spirit calls into the body of Christ.</p>",
    "6": "<p><em>Shadow.</em> &ldquo;All their neighbors aided them&hellip; besides all that was freely offered.&rdquo; The voluntary, generous support of the Gentile neighbors for the returning community echoes the tabernacle-building pattern (Exod 35:20-29) and anticipates the church&rsquo;s experience: &ldquo;the grace of God that has been given among the churches of Macedonia&hellip; their abundance of joy and their extreme poverty have overflowed in a wealth of generosity&rdquo; (2 Cor 8:1-2). The Spirit of Christ produces the same generous response in every generation.</p>",
    "7": "<p><em>Type.</em> Cyrus brings out the vessels of the house of YHWH that Nebuchadnezzar had carried away. The return of the sacred vessels is the reversal of the conquest — what the enemy took is restored. Christ&rsquo;s mission is defined by this same restorative logic: &ldquo;The Son of God appeared for this purpose, to destroy the works of the devil&rdquo; (1 John 3:8). Everything plundered in the Fall — the divine image in humanity, the access to God&rsquo;s presence, the calling to serve as priests — is restored in Christ. He is the one who brings back what was carried off.</p>",
    "8": "<p><em>Theme.</em> Sheshbazzar the prince of Judah receives the vessels — a Davidic figure taking formal possession of the sacred objects. Christ as the Davidic heir is the one through whom all the sacred treasures of the covenant return to their proper place: the law written on hearts (Jer 31:33), the Spirit poured out (Ezek 36:27), the presence of God dwelling with humanity (Rev 21:3). The Davidic prince receiving the vessels is the type; Christ receiving &ldquo;all the fullness of God&rdquo; (Col 1:19) and distributing it to his people is the reality.</p>",
    "9": "<p><em>Shadow.</em> The inventory: 30 gold dishes, 1,000 silver dishes, 29 censers — the beginning of the detailed accounting of restored temple treasure. In Christ, all the spiritual riches stored up in him are distributed to his people: &ldquo;from his fullness we have all received, grace upon grace&rdquo; (John 1:16). Paul prays that believers &ldquo;may have strength to comprehend with all the saints what is the breadth and length and height and depth&rdquo; of Christ&rsquo;s love (Eph 3:18) — the immeasurable treasury of the one in whom all the fullness of deity dwells bodily (Col 2:9).</p>",
    "10": "<p><em>Shadow.</em> Gold bowls (30), duplicate silver bowls (410), other vessels (1,000) — the enumeration continues. The preserved temple vessels, maintained intact through the entire Babylonian exile, speak to the indestructibility of what God guards. Christ is &ldquo;the same yesterday and today and forever&rdquo; (Heb 13:8) — all that he is and has cannot be diminished by any exile, defeat, or cultural pressure. His resources are not depleted by use; they are inexhaustible (Eph 3:8, &ldquo;unsearchable riches of Christ&rdquo;).</p>",
    "11": "<p><em>Type.</em> Total: 5,400 vessels brought back complete. Nothing was lost. Christ&rsquo;s high-priestly claim: &ldquo;I have not lost one of those whom you gave me&rdquo; (John 17:12; 18:9). The complete recovery of all the temple vessels is the type of Christ&rsquo;s perfect preservation of all who are given to him by the Father. As no single vessel was lost in the journey from Babylon to Jerusalem, so no member of Christ&rsquo;s flock is lost in the journey from exile to the Father&rsquo;s house (John 10:28-29).</p>"
  },
  "2": {
    "1": "<p><em>Theme.</em> The census of those who returned from Babylonian captivity — the counted, named, recorded remnant who answer the call to return. Paul identifies this as the pattern of the true Israel: &ldquo;so too at the present time there is a remnant chosen by grace&rdquo; (Rom 11:5). Christ constitutes the remnant around himself — all who belong to him are named, counted, and recorded in the book of life (Rev 21:27; Phil 4:3). The post-exilic census list is the OT form of the eschatological roll call.</p>",
    "2": "<p><em>Type.</em> Zerubbabel heads the list of leaders. Zerubbabel appears in Matthew&rsquo;s genealogy of Jesus (Matt 1:12-13) as a direct ancestor — making the leader of the post-exilic return a forebear of the one who accomplishes the ultimate return from exile. Alongside Jeshua the high priest, Zerubbabel forms the kingly-priestly pair that Zechariah interprets messianically (Zech 4:11-14; 6:13): a Davidic king and a high priest who together prefigure the single person who unites both offices permanently in Christ.</p>",
    "3": "<p><em>Theme.</em> The people of Parosh (2,172) — one of the foundational families of the restored community. Every family in the returning community is a witness to the covenant-faithfulness of YHWH who preserved his people through exile. Christ is the fulfillment of that preservation: he is the one through whom the divine faithfulness expressed in the exile-and-return becomes the permanent reality of adoption into God&rsquo;s family (Gal 4:5-7). Each family group is a testimony to the same divine <em>ḥesed</em> that endures forever.</p>",
    "4": "<p><em>Theme.</em> The people of Shephatiah (372) — continuing the enumeration of the returned remnant. The sheer variety of family groups returning together, each counted, each named in the official record, prefigures the eschatological assembly: &ldquo;a great multitude that no one could number, from every nation, from all tribes and peoples and languages, standing before the throne and before the Lamb&rdquo; (Rev 7:9). In Christ, the assembly is larger than any census could capture — yet each member is individually known (John 10:3, &ldquo;he calls his own sheep by name&rdquo;).</p>",
    "5": "<p><em>Theme.</em> The people of Arah (775) — each family group answers the divine summons to return. The pattern of a remnant responding to the call echoes through Scripture to the NT: &ldquo;many are called, but few are chosen&rdquo; (Matt 22:14). Christ is the one who issues the great call (Matt 11:28, &ldquo;come to me, all who labor and are heavy laden&rdquo;) and who preserves those who respond: &ldquo;all that the Father gives me will come to me, and whoever comes to me I will never cast out&rdquo; (John 6:37).</p>",
    "6": "<p><em>Theme.</em> The people of Pahath-moab (2,812) — one of the larger families, linked to the Mosaic tradition of governance in Moab&rsquo;s territory. The return of families associated with the pre-exilic administrative history of Judah signals the restoration of the covenant order. Christ is the fulfillment of the covenant administration — the &ldquo;mediator of a new covenant&rdquo; (Heb 9:15; 12:24) who establishes the definitive arrangement between God and his people.</p>",
    "7": "<p><em>Theme.</em> The people of Elam (1,254) — among the larger returning families. The name Elam points to the east, to Mesopotamia, to the scattered diaspora that responded to the divine call. Christ&rsquo;s commission is to gather the scattered: &ldquo;he should gather into one the children of God who are scattered abroad&rdquo; (John 11:52). The return from Elam is the type; the gathering from &ldquo;every nation, tribe, people and language&rdquo; (Rev 7:9) is the antitype.</p>",
    "8": "<p><em>Theme.</em> The people of Zattu (945) — continuing the enumeration. The numerical precision of the list signals divine superintendence of the community&rsquo;s formation. Christ knows the precise number of his own: &ldquo;I am the good shepherd; I know my sheep and my sheep know me&rdquo; (John 10:14). The Shepherd&rsquo;s knowledge of each sheep individually is the fulfillment of the census-keeper&rsquo;s enumeration in Ezra 2.</p>",
    "9": "<p><em>Theme.</em> The people of Zaccai (760) — &ldquo;pure&rdquo; or &ldquo;innocent&rdquo; by name. In the returning community, names like &ldquo;innocent&rdquo; point to the aspiration of the restored covenant people to be a holy community. Christ is the one who makes the impure pure: &ldquo;you were washed, you were sanctified, you were justified in the name of the Lord Jesus Christ and by the Spirit of our God&rdquo; (1 Cor 6:11). The family named &ldquo;pure&rdquo; anticipates the people whom Christ will make actually pure.</p>",
    "10": "<p><em>Theme.</em> The people of Bani (642) — one of the most frequently named families in the post-exilic community. Their repeated appearances across Ezra-Nehemiah (Ezra 8:10; 10:29, 34, 38; Neh 8:7; 10:13-14) show the continuity of specific family lines in covenant service. Christ is &ldquo;the same yesterday and today and forever&rdquo; (Heb 13:8) — the continuity that transcends family lines and generations, binding the covenant community across all time.</p>",
    "11": "<p><em>Theme.</em> The people of Bebai (623) — continuing the census. The list of returning families is a testimony to the covenant&rsquo;s survival through Babylon&rsquo;s attempts to absorb and destroy Israel&rsquo;s distinctive identity. The church similarly maintains its distinct identity through cultural pressures. Christ&rsquo;s promise ensures the church&rsquo;s survival: &ldquo;the gates of Hades will not prevail against it&rdquo; (Matt 16:18).</p>",
    "12": "<p><em>Theme.</em> The people of Azgad (1,222) — one of the larger families. The name means &ldquo;Gad is strong&rdquo; — a tribal name kept alive in the diaspora. The preservation of tribal names through the exile shows the community&rsquo;s determined maintenance of its Israelite identity. Christ fulfills the twelve-tribe structure of God&rsquo;s people: his twelve apostles will &ldquo;sit on twelve thrones, judging the twelve tribes of Israel&rdquo; (Matt 19:28), completing the tribal identity in eschatological governance.</p>",
    "13": "<p><em>Theme.</em> The people of Adonikam (666) — whose name means &ldquo;my lord has arisen.&rdquo; The theophoric element &ldquo;my lord has arisen&rdquo; embedded in a family name across generations finds its ultimate referent in the resurrection: Christ is the Lord who has truly risen (<em>ʾăḏōnî qām</em>). Every pre-Christian theophoric name that celebrated divine arising was an unconscious anticipation of Easter morning.</p>",
    "14": "<p><em>Theme.</em> The people of Bigvai (2,056) — the name is Persian origin, meaning &ldquo;happy&rdquo; or &ldquo;fortunate.&rdquo; A family that adopted a Persian name while maintaining its Jewish covenant identity shows the diaspora&rsquo;s navigation of cultural accommodation without loss of core identity. Christ calls his people to be &ldquo;in the world but not of the world&rdquo; (John 17:14-16) — the same navigation between engagement and distinctness that the diaspora families exemplified.</p>",
    "15": "<p><em>Theme.</em> The people of Adin (454) — &ldquo;ornament&rdquo; or &ldquo;delicate.&rdquo; The seemingly fragile (few in number, modestly named) are included in the covenant community alongside the strong and many. Christ&rsquo;s election principle inverts human expectation: &ldquo;God chose what is weak in the world to shame the strong&rdquo; (1 Cor 1:27). The small families in Ezra&rsquo;s list are the type of the communities that Christ&rsquo;s gospel tends to gather.</p>",
    "16": "<p><em>Theme.</em> The people of Ater, of Hezekiah (98) — a family that honored the reforming king Hezekiah by naming a sub-branch after him. The memory of the righteous king kept alive in a diaspora family name is a small act of covenant loyalty. Christ is the one in whom all the righteous kings&rsquo; aspirations are fulfilled: Hezekiah prayed that the Northern exiles could keep the Passover (2 Chr 30:18-19); Christ extends the Passover covenant to all peoples (1 Cor 5:7-8).</p>",
    "17": "<p><em>Theme.</em> The people of Bezai (323) — one of those who will sign the covenant renewal under Nehemiah (Neh 10:18). Their covenant-signing points forward to the new covenant signed in Christ&rsquo;s blood: &ldquo;This cup is the new covenant in my blood, which is poured out for you&rdquo; (Luke 22:20). Every covenant renewal in Israel&rsquo;s history (Josiah, Ezra, Nehemiah) is a type of the final, indestructible covenant established at the Last Supper.</p>",
    "18": "<p><em>Theme.</em> The people of Jorah (112) — a small family whose return is counted and recorded. The careful enumeration of even the smallest families reflects the same principle that Christ articulates: &ldquo;Are not two sparrows sold for a penny? And not one of them will fall to the ground apart from your Father&rdquo; (Matt 10:29). The divine accounting that tracks 112 returned exiles is the same divine care that numbers the hairs of believers&rsquo; heads (Matt 10:30).</p>",
    "19": "<p><em>Theme.</em> The people of Hashum (223) — one of the families represented among those who stood with Ezra when the Torah was read publicly (Neh 8:4). The connection between census and Torah-reading suggests that membership in the community is defined by both lineage (the list) and word (the reading). Christ defines his community similarly: by birth (John 3:3-8, born of the Spirit) and by his word (John 17:17, sanctified in the truth).</p>",
    "20": "<p><em>Theme.</em> The people of Gibbar (95) — a small family associated with the Benjaminite region near Gibeon. The return of communities from every corner of Judah and Benjamin reconstitutes the full geographic extent of the southern kingdom. Christ&rsquo;s mission similarly gathers from the geographic and social margins: &ldquo;You will be my witnesses in Jerusalem and in all Judea and Samaria, and to the end of the earth&rdquo; (Acts 1:8) — center to periphery, near to far, small communities to great.</p>",
    "21": "<p><em>Direct.</em> The men of Bethlehem (123) — the hometown of David, the ancestor of the Messiah. Bethlehem&rsquo;s inclusion in the census is understated: the town that produced the greatest king now sends 123 men to the restoration. The continuity of Bethlehem&rsquo;s covenant community from the exile through the return to the birth of Christ (Mic 5:2: &ldquo;from you, Bethlehem Ephrathah&hellip; shall come forth for me one who is to be ruler in Israel&rdquo;) makes even this census entry a thread in the narrative leading to Christmas.</p>",
    "22": "<p><em>Theme.</em> The men of Netophah (56) — a Judean highland town associated with Levitical singers (1 Chr 9:16; Neh 12:28). The musicians who return from Netophah carry forward the tradition of sacred song. Christ fulfills the temple music tradition: Heb 2:12 applies Ps 22:22 to Christ (&ldquo;in the midst of the congregation I will sing your praise&rdquo;) — the song leader of the heavenly assembly is the one in whom all temple music finds its true voice.</p>",
    "23": "<p><em>Theme.</em> The men of Anathoth (128) — hometown of Jeremiah, the prophet who suffered most for speaking the truth about the exile and who promised the new covenant (Jer 31:31-34). The community from Anathoth carries with it the memory of the prophet who paid the highest price for faithfulness. Christ, like Jeremiah, was rejected by his own people (John 1:11), suffered in their service, and inaugurated the new covenant that Jeremiah promised (Luke 22:20).</p>",
    "24": "<p><em>Theme.</em> The men of Azmaveth (42) — &ldquo;death is strong.&rdquo; A town name meaning &ldquo;death is strong&rdquo; among the returned community points to the central reality of the exile experience: the community has passed through the equivalent of death (the exile as national death) and returned. Christ&rsquo;s resurrection is the ultimate answer to &ldquo;death is strong&rdquo; — &ldquo;Death is swallowed up in victory. O death, where is your victory? O death, where is your sting?&rdquo; (1 Cor 15:54-55).</p>",
    "25": "<p><em>Shadow.</em> The men of Kiriath-jearim, Chephirah, and Beeroth (743) — including Kiriath-jearim, where the ark rested for 20 years before David brought it to Jerusalem. The town associated with the ark&rsquo;s resting place sends its people to rebuild the temple that will eventually house the ark&rsquo;s successor. Christ is &ldquo;the true ark of the covenant&rdquo; in whom God&rsquo;s presence truly dwells — not behind a curtain and not in a wooden box but in a body of flesh, permanently available (Rev 11:19; 21:22).</p>",
    "26": "<p><em>Theme.</em> The men of Ramah and Geba (621) — including Ramah, where Rachel wept for her exiled children (Jer 31:15). Matthew applies this to Herod&rsquo;s slaughter of the innocents (Matt 2:18) — the community of Rachel&rsquo;s weeping produces the community that welcomes the Messiah. The grief of Ramah recorded in Jeremiah and echoed in Matthew frames the entire story of exile and return: Christ is the end of Rachel&rsquo;s weeping, the comfort promised in Jer 31:16 (&ldquo;there is hope for your future, declares YHWH; your children shall come back&rdquo;).</p>",
    "27": "<p><em>Theme.</em> The men of Michmas (122) — associated with Jonathan&rsquo;s great faith-victory over the Philistines (1 Sam 14). The return of the Michmas community carries the memory of covenant faith that accomplishes what appears humanly impossible. Christ embodies this principle absolutely: &ldquo;with God all things are possible&rdquo; (Matt 19:26); his resurrection is the definitive victory achieved through trust in the Father rather than human strength.</p>",
    "28": "<p><em>Theme.</em> The men of Bethel and Ai (223) — including Bethel, where Jacob dreamed of the ladder between heaven and earth (Gen 28:10-19). Jacob called it &ldquo;the house of God and the gate of heaven.&rdquo; Christ identifies himself as the fulfillment of this vision: &ldquo;you will see heaven opened, and the angels of God ascending and descending on the Son of Man&rdquo; (John 1:51). Christ is the true Bethel — the gate of heaven, the house of God, the place where earth meets the divine presence.</p>",
    "29": "<p><em>Theme.</em> The men of Nebo (52) — a small community returning from the eastern Benjaminite region. The name Nebo connects to Mount Nebo where Moses died within sight of the promised land (Deut 34:1-5). Moses saw the land from a distance but could not enter; the returning community embodies the entry into the land that Moses could only view. Christ fulfills Moses&rsquo; ministry: he brings his people not merely into the earthly land but into the eternal rest that the land always promised (Heb 4:8-11).</p>",
    "30": "<p><em>Theme.</em> The men of Magbish (156) — a town not identified elsewhere in the biblical record. The inclusion of communities whose exact identity is uncertain in the official census reflects the same principle as Christ&rsquo;s gathering: &ldquo;I have other sheep that are not of this fold; I must bring them also&rdquo; (John 10:16). The unnamed, the marginal, the communities on the edge of the record are included in the comprehensive gathering of God&rsquo;s people.</p>",
    "31": "<p><em>Theme.</em> The men of the other Elam (1,254) — a second large family bearing the same name and the same number as the first (v7). The repetition of the Elam family at the same count is a textual peculiarity that reminds the reader of the multiplicity and diversity within a unified census. Christ gathers a diverse people united in him: &ldquo;there is neither Jew nor Greek, there is neither slave nor free, there is no male and female, for you are all one in Christ Jesus&rdquo; (Gal 3:28).</p>",
    "32": "<p><em>Theme.</em> The men of Harim (320) — a family that appears both among the laity (here) and the priests (v39), reflecting the complexity of post-exilic community structure. The overlap between lay and priestly Harim families anticipates the NT&rsquo;s dissolution of the lay-priest boundary: in Christ, all believers are a &ldquo;royal priesthood&rdquo; (1 Pet 2:9), the distinction between clergy and laity permanently reconfigured by the one who is both the eternal high priest and the representative man.</p>",
    "33": "<p><em>Theme.</em> The men of Lod, Hadid, and Ono (725) — towns of the coastal plain, the commercial gateway of the Levant. Their inclusion signals that the restoration extends to the lowland trading centers, not only the highland religious center of Jerusalem. Christ&rsquo;s kingdom encompasses all geographies and social classes: merchants and traders, highlanders and lowlanders, all are called into the one community (Rev 5:9, &ldquo;from every tribe and language and people and nation&rdquo;).</p>",
    "34": "<p><em>Theme.</em> The men of Jericho (345) — the city of Joshua&rsquo;s first conquest. The return to Jericho completes the circuit of Israel&rsquo;s history: from Joshua&rsquo;s entry by conquest to Zerubbabel&rsquo;s entry by grace. Christ is the greater Joshua (Jesus = Joshua = &ldquo;YHWH saves&rdquo;) who leads a greater return to a greater land. Heb 4:8: &ldquo;if Joshua had given them rest, God would not have spoken of another day later on&rdquo; — the rest that Jericho&rsquo;s conquest began is completed in Christ.</p>",
    "35": "<p><em>Theme.</em> The men of Senaah (3,630) — the largest single entry in the entire list, a community whose size dwarfs all others. The largest family in the census reminds the reader that the covenant community includes the overwhelming majority alongside the notable minority. Christ&rsquo;s gathering is similarly both particular (named, counted) and vast (&ldquo;a great multitude that no one could number,&rdquo; Rev 7:9). The great and the small are equally contained in the census of the redeemed.</p>",
    "36": "<p><em>Shadow.</em> The priestly families begin: the sons of Jedaiah (973). The Davidic priestly divisions return to staff the second temple — the institutional continuity of the Aaronic priesthood through the exile is preserved. Christ fulfills and supersedes the Aaronic priesthood: &ldquo;he holds his priesthood permanently, because he continues forever&rdquo; (Heb 7:24), and through him all believers become priests (1 Pet 2:9; Rev 1:6). The returning priests are the shadow of the one priest in whom all priesthood is perfected.</p>",
    "37": "<p><em>Shadow.</em> The sons of Immer (1,052) — one of the 24 Davidic priestly divisions. The 24 priestly divisions rotating through temple service (1 Chr 24) become in Revelation the 24 elders who worship permanently before the throne of God and the Lamb (Rev 4:4, 10; 5:8-10). The 24 rotating priests who maintained the earthly temple worship are transformed in Christ into the 24 permanent worshipers in the eternal temple.</p>",
    "38": "<p><em>Shadow.</em> The sons of Pashhur (1,247) — the priestly family associated with opposition to Jeremiah (Jer 20:1-6). Their return despite that history of resisting the prophetic word is an act of grace. Christ receives those who once opposed his messengers: Saul of Tarsus, who persecuted the church, became Paul the apostle (Acts 9). The inclusion of Pashhur&rsquo;s descendants in the covenant community is a type of the grace that incorporates former opponents into God&rsquo;s people.</p>",
    "39": "<p><em>Shadow.</em> The sons of Harim (1,017) — completing the four returning priestly families: 4,289 total priests. The priestly community&rsquo;s return is essential to the restored temple&rsquo;s function. Christ as the one perfect high priest (Heb 7:26-27) renders the entire priestly system complete and then obsolete simultaneously: complete, because all four priestly families have returned; obsolete, because &ldquo;when there is a change in the priesthood, there is necessarily a change in the law as well&rdquo; (Heb 7:12). The priestly return is the last flourishing of the old order before the new.</p>",
    "40": "<p><em>Shadow.</em> The Levites: sons of Jeshua and Kadmiel (74) — dramatically fewer than the 4,289 priests. The shortage of Levites in the restoration foreshadows the ministry challenges of the new covenant community: the harvest is plentiful but the laborers are few (Matt 9:37-38). Christ addresses this shortage by equipping all believers as ministers (Eph 4:11-12) rather than concentrating ministry in a small specialized class. The Levitical shortage is resolved in the new covenant by the Spirit&rsquo;s distribution of gifts to all (1 Cor 12:4-11).</p>",
    "41": "<p><em>Shadow.</em> The singers, the sons of Asaph (128) — the only musical guild to return from exile. The Asaphite tradition was known for lament psalms (Pss 73-83) that wrestled honestly with suffering and divine hiddenness — exactly the tradition needed by a community emerging from exile. Christ &ldquo;in the midst of the congregation will sing praise&rdquo; (Heb 2:12, citing Ps 22:22) — the crucified one who cried &ldquo;My God, my God, why have you forsaken me?&rdquo; is also the worship leader of the new covenant assembly.</p>",
    "42": "<p><em>Shadow.</em> The gatekeepers (139) — six families guarding the temple entrances. Christ is &ldquo;the door of the sheep&rdquo; (John 10:7) — the true gatekeeper who controls access to the Father. The physical gatekeepers of Ezra 2 perform in the earthly temple what Christ fulfills in the eternal temple: securing the holy precincts, allowing the worthy to enter, protecting the sacred from contamination. &ldquo;I am the gate; whoever enters through me will be saved&rdquo; (John 10:9).</p>",
    "43": "<p><em>Shadow.</em> The Nethinim begin — temple servants of non-Israelite origin. Their inclusion in the official census of the returned covenant community is theologically significant: people of foreign and servile origin are counted among God&rsquo;s people. Christ&rsquo;s inclusiveness surpasses even this: &ldquo;there is neither Jew nor Greek, slave nor free, male nor female, for you are all one in Christ Jesus&rdquo; (Gal 3:28). The Nethinim&rsquo;s inclusion anticipates the full Gentile inclusion that Christ achieves.</p>",
    "44": "<p><em>Theme.</em> Keros, Siaha, Padon — Nethinim families with non-Israelite names. Their diverse ethnic origins are preserved in the official record, not hidden. Christ gathers a people whose diversity is honored rather than erased: &ldquo;from every nation, from all tribes and peoples and languages, standing before the throne&rdquo; (Rev 7:9). The ethnic particularity of each Nethinim family is the OT form of the eschatological vision where each nation&rsquo;s distinct identity is preserved in the new creation (Rev 21:24-26).</p>",
    "45": "<p><em>Theme.</em> Lebana, Hagaba, Akkub — Nethinim continuing. The layering of lists within lists (Nethinim within the larger census) reflects the complexity of the covenant community: it is not monolithic but composed of communities within communities, each with its distinct history and function. Christ&rsquo;s body is similarly complex: &ldquo;There are varieties of gifts, but the same Spirit; varieties of service, but the same Lord; varieties of activities, but it is the same God who empowers them all in everyone&rdquo; (1 Cor 12:4-6).</p>",
    "46": "<p><em>Theme.</em> Hagab, Shalmai, Hanan — more Nethinim. The name Hanan means &ldquo;gracious&rdquo; — YHWH&rsquo;s grace expressed in a personal name, carried by a temple servant family. The grace embedded in the name of the lowliest temple servants is a prophetic word: grace characterizes the entire operation of the temple — it is not human achievement that maintains YHWH&rsquo;s dwelling but divine gracious initiative. Christ is the ultimate expression of this: &ldquo;from his fullness we have all received, grace upon grace&rdquo; (John 1:16).</p>",
    "47": "<p><em>Theme.</em> Giddel (&ldquo;he has made great&rdquo;), Gahar, Reaiah (&ldquo;YHWH has seen&rdquo;) — Nethinim names that embed theological affirmations. &ldquo;YHWH has seen&rdquo; in a Nethinim family name echoes Hagar&rsquo;s cry at the well: &ldquo;You are a God of seeing&rdquo; (Gen 16:13, &ldquo;El-roi&rdquo;). Christ is the God who sees the marginalized: he sees Zacchaeus in the tree (Luke 19:5), the woman at the well (John 4:7-10), the man born blind (John 9:1). The Nethinim who named their son &ldquo;YHWH has seen&rdquo; were asserting the divine attention that Christ embodies.</p>",
    "48": "<p><em>Theme.</em> Rezin, Nekoda, Gazzam — Nethinim continuing. The name Rezin (an Aramean king&rsquo;s name) embedded in a temple servant family illustrates how the enemies of Israel become servants in YHWH&rsquo;s house. This is the OT preview of Eph 2:14-16: Christ has &ldquo;broken down in his flesh the dividing wall of hostility&rdquo; between former enemies, &ldquo;so making peace.&rdquo; Israel&rsquo;s enemies&rsquo; descendants serving in the temple anticipate the cosmic reconciliation Christ achieves.</p>",
    "49": "<p><em>Theme.</em> Uzza, Paseah, Besai — Nethinim. The name Uzza in this context carries a transformed significance from the tragic Uzza who died touching the ark (2 Sam 6:7). A Nethinim family bearing this name serves in the temple without the death that the ark&rsquo;s holiness once demanded. Christ&rsquo;s high-priestly work transforms the holy from the dangerous into the welcoming: &ldquo;let us draw near with a true heart in full assurance of faith&rdquo; (Heb 10:22). The ark&rsquo;s lethal holiness becomes the mercy seat&rsquo;s life-giving grace in Christ.</p>",
    "50": "<p><em>Theme.</em> Asnah, Meunim, Nephisim — Nethinim including the Meunites (former enemies, 2 Chr 20:1; 26:7) now serving in the temple. The transformation of an enemy people into temple servants is the earthly type of the cosmic reconciliation in Christ: &ldquo;God was in Christ reconciling the world to himself, not counting their trespasses against them&rdquo; (2 Cor 5:19). Former adversaries become ministers in the house of God — the very thing Paul describes as the &ldquo;ministry of reconciliation&rdquo; given to the church.</p>",
    "51": "<p><em>Theme.</em> Bakbuk, Hakupha, Harhur — Nethinim with names suggesting diverse geographical origins including Egypt (Hakupha possibly Egyptian). The gathering of people from multiple nations into temple service prefigures Isa 56:6-7: &ldquo;foreigners who join themselves to YHWH&hellip; these I will bring to my holy mountain, and make them joyful in my house of prayer&rdquo; — the text Jesus cited when cleansing the temple (Mark 11:17). The Nethinim of Ezra 2 are the early fulfillment; the church from all nations is the complete fulfillment.</p>",
    "52": "<p><em>Theme.</em> Bazluth, Mehida, Harsha — more Nethinim families completing their service across the generations of exile and return. The persistence of these servant families through the exile — maintaining their identity, preserving their lineage records, returning to their function — reflects the same faithfulness that characterizes Christ&rsquo;s servants: &ldquo;it is required of stewards that they be found faithful&rdquo; (1 Cor 4:2). Faithful service across generations of difficulty is honored in the census.</p>",
    "53": "<p><em>Theme.</em> Barkos, Sisera, Temah — Nethinim including descendants of Sisera the enemy commander (Judg 4). His descendant now serves YHWH in the restored temple — the ultimate reversal. Christ&rsquo;s gospel accomplishes this reversal universally: &ldquo;While we were enemies we were reconciled to God by the death of his Son&rdquo; (Rom 5:10). The genealogical enemy-to-servant transformation in the Nethinim list is the social embodiment of theological reconciliation.</p>",
    "54": "<p><em>Theme.</em> Neziah, Hatipha — the final Nethinim families before Solomon&rsquo;s servants. The comprehensive enumeration of even the smallest Nethinim families in the official census reflects Christ&rsquo;s assurance: &ldquo;even the hairs of your head are all numbered&rdquo; (Matt 10:30). Nothing in God&rsquo;s reckoning is too small to count. The Nethinim&rsquo;s inclusion in the covenant census is the OT testimony to what Christ declares explicitly: every member of God&rsquo;s community is individually known and numbered.</p>",
    "55": "<p><em>Shadow.</em> The sons of Solomon&rsquo;s servants begin — descendants of the Canaanite labor force dedicated to the temple service (1 Kgs 9:20-21). Solomon conscripted the remaining Canaanites who had not been expelled; their descendants now voluntarily return to serve in the restored temple. The voluntary return of families whose origins were in compelled service is the shadow of Christ&rsquo;s transformation: those who were &ldquo;slaves to sin&rdquo; (Rom 6:17) become willing servants of righteousness, &ldquo;enslaved to God&rdquo; (Rom 6:22) freely and joyfully.</p>",
    "56": "<p><em>Theme.</em> Jaala, Darkon, Giddel — Solomon&rsquo;s servants continuing. Their return alongside the priests, Levites, and Nethinim demonstrates the comprehensiveness of the covenant community&rsquo;s reconstitution. Every rank and function returns together. Christ&rsquo;s body similarly requires every member: &ldquo;the eye cannot say to the hand, I have no need of you, nor again the head to the feet, I have no need of you&rdquo; (1 Cor 12:21). Dignity belongs to every function in the community.</p>",
    "57": "<p><em>Theme.</em> Shephatiah, Hattil, Pochereth-hazzebaim, and Ami — completing Solomon&rsquo;s servants. The last named members of the temple service hierarchy are among those whose origins are most distant from the covenant people — yet they are enumerated with the same precision as the priestly families. Christ&rsquo;s kingdom inverts the hierarchy: &ldquo;many who are first will be last, and the last first&rdquo; (Matt 19:30); those listed last in the human record may be first in the divine.</p>",
    "58": "<p><em>Theme.</em> Total Nethinim and Solomon&rsquo;s servants: 392. Their combined number — over 10% of the non-priestly non-Levitical temple personnel — shows how central the service class was to the temple&rsquo;s operation. Christ came &ldquo;not to be served but to serve&rdquo; (Matt 20:28), identifying himself with the servant class rather than the privileged class. The Nethinim and Solomon&rsquo;s servants are the people whose role most closely mirrors what Christ himself models.</p>",
    "59": "<p><em>Theme.</em> Those who cannot prove their Israelite ancestry — the genealogical crisis. People from Babylonian Jewish communities who lack lineage records are in suspension: present, but unverified. The fundamental human question of identity and belonging — &ldquo;am I truly one of God&rsquo;s people?&rdquo; — finds its resolution not in human genealogical records but in the divine act of adoption. &ldquo;You received the Spirit of adoption as sons, by whom we cry, &lsquo;Abba! Father!&rsquo;&rdquo; (Rom 8:15). Christ resolves the identity question permanently.</p>",
    "60": "<p><em>Theme.</em> Delaiah, Tobiah, Nekoda — 652 persons without verified lineage. Their uncertain status in the restored community is the social form of a universal human condition: every human being is uncertain of their standing before God without divine attestation. Christ provides the divine attestation: &ldquo;The Spirit himself bears witness with our spirit that we are children of God&rdquo; (Rom 8:16). No human genealogical record is required; the Spirit&rsquo;s witness is the only certificate of belonging that ultimately matters.</p>",
    "61": "<p><em>Shadow.</em> The priestly families without verified genealogy — sons of Habaiah, Hakkoz, Barzillai — are excluded from priestly service until the issue can be divinely resolved. The suspension of their priestly identity &ldquo;until a priest should arise with Urim and Thummim&rdquo; (v63) points to a future definitive resolution. Christ is the high priest who resolves all ambiguity: he is both the oracle and the interpreter, the priest and the one who authenticates priests (Heb 7:11-17). In him, every identity question is settled.</p>",
    "62": "<p><em>Shadow.</em> Those excluded from the priesthood &ldquo;as unclean&rdquo; — their priestly status suspended pending verification. The exclusion from serving at the altar because one cannot prove legitimate access is the OT form of a universal spiritual reality: no human being has inherent right of access to God. Christ alone has inherent right — &ldquo;I am the way, and the truth, and the life; no one comes to the Father except through me&rdquo; (John 14:6). In him, excluded people become priests: &ldquo;you have made them a kingdom and priests to our God&rdquo; (Rev 5:10).</p>",
    "63": "<p><em>Direct.</em> The governor decrees the excluded priests cannot eat the most holy food &ldquo;until a priest arises with the Urim and Thummim.&rdquo; The Urim and Thummim had functioned as the high priest&rsquo;s divination instrument for determining YHWH&rsquo;s verdict (Exod 28:30; Num 27:21). By the post-exilic period, they were no longer in use (Neh 7:65 repeats the same formula). The resolution &ldquo;until a priest arises with Urim and Thummim&rdquo; is consciously eschatological — it awaits the coming priest who can directly mediate divine verdicts. Christ is that priest: he does not cast lots to discover YHWH&rsquo;s will; he is the Word of God, who declares it directly. In him, every identity verdict is rendered with perfect accuracy.</p>",
    "64": "<p><em>Theme.</em> The whole assembly: 42,360. The single total that supersedes and encompasses all the individual sub-totals. Christ is the one in whom all the diverse members of God&rsquo;s community are unified: &ldquo;there is one body and one Spirit, just as you were called to the one hope that belongs to your call, one Lord, one faith, one baptism, one God and Father of all&rdquo; (Eph 4:4-6). The census&rsquo;s unified total — 42,360 named individuals becoming one assembly — is the social image of the unity Christ creates across all diversity.</p>",
    "65": "<p><em>Theme.</em> 7,337 servants and 200 singers — the full community includes not only the officially enumerated households but those in dependent roles. Christ&rsquo;s community similarly includes the otherwise invisible: &ldquo;there is no longer slave or free&rdquo; (Gal 3:28); the secular singers who travel with the community are as much part of the return as the priests. Christ&rsquo;s inclusive gathering neither ignores social distinctions (they are acknowledged) nor allows them to determine ultimate belonging (they are transcended in him).</p>",
    "66": "<p><em>Theme.</em> 736 horses — a mark of social standing in the ancient world. The wealthy and prominent are part of the returning community. Christ does not exclude the rich: &ldquo;For God so loved the world&rdquo; (John 3:16) encompasses every social stratum. His message to the rich is invitation, not exclusion (though with a sharper demand, Matt 19:21-24). The mix of wealthy horse-owners and Nethinim servants in one census reflects the cross-section of humanity that Christ gathers.</p>",
    "67": "<p><em>Theme.</em> 6,720 donkeys — the primary transportation of ordinary people, vastly outnumbering the prestige horses. The ordinary person&rsquo;s beast of burden dominates the census. Christ himself entered Jerusalem on a donkey (Matt 21:5, citing Zech 9:9) — identifying with the ordinary, the humble, the non-prestige mode of transport. His is a kingdom where the donkey is more representative than the warhorse.</p>",
    "68": "<p><em>Shadow.</em> &ldquo;Some of the heads of families made freewill offerings for the house of God.&rdquo; The first act of the community upon arriving at the temple site is voluntary, generous giving — no external compulsion, only the stirring of the Spirit. Christ calls for exactly this: &ldquo;each one must give as he has decided in his heart, not reluctantly or under compulsion, for God loves a cheerful giver&rdquo; (2 Cor 9:7). The freewill offerings of Ezra 2 are the OT template for the new covenant community&rsquo;s financial life — willing, joyful, Spirit-motivated generosity.</p>",
    "69": "<p><em>Theme.</em> 61,000 darics of gold, 5,000 minas of silver, 100 priestly garments — the immediate provision of resources for the work. The sufficiency of provision for God&rsquo;s building projects reflects the principle Paul articulates: &ldquo;my God will supply every need of yours according to his riches in glory in Christ Jesus&rdquo; (Phil 4:19). The community does not begin the work wondering whether resources will come; they give first and build on that foundation. Faith expressed in giving precedes building.</p>",
    "70": "<p><em>Theme.</em> Settlement summary — priests and Levites in Jerusalem, others in their towns; everyone in their places. The orderly distribution of the returning community across the land is the social form of the body-of-Christ principle: each member placed where they belong. &ldquo;God arranged the members in the body, each one of them, as he chose&rdquo; (1 Cor 12:18). The census that began in v1 with the naming of individuals ends with their placement — every person known, counted, and positioned in the community God is rebuilding.</p>"
  },
  "3": {
    "1": "<p><em>Theme.</em> The seventh month — the most sacred month of the Jewish calendar (Trumpets, Atonement, Tabernacles) — and the community gathers &ldquo;as one man.&rdquo; The unity of the assembly prefigures the church&rsquo;s gathering: &ldquo;they were all together in one place&rdquo; (Acts 2:1) when the Spirit came at Pentecost — itself another sacred season. Christ is the one who makes &ldquo;one new man&rdquo; from divided humanity (Eph 2:15), gathering the scattered community into the &ldquo;one body&rdquo; (Eph 4:4).</p>",
    "2": "<p><em>Type.</em> Jeshua and Zerubbabel build the altar of the God of Israel. The Davidic prince (Zerubbabel) and the high priest (Jeshua) act together to restore sacrifice — the kingly-priestly partnership that Zechariah will interpret as a type of the one who &ldquo;shall be a priest on his throne&rdquo; (Zech 6:13). Christ, who is both King of kings and eternal High Priest, is the one in whom this dual office is permanently united. The altar they build is the shadow; Christ himself is both the altar and the sacrifice (Heb 13:10-12).</p>",
    "3": "<p><em>Theme.</em> &ldquo;They set the altar in its place, for fear was on them because of the peoples of the lands.&rdquo; The act of worship despite fear — establishing the altar before any walls of protection were built — models the principle that access to God through the altar is the community&rsquo;s primary defense. Christ is the altar (Heb 13:10) and the mediator through whom the hostile world is overcome: &ldquo;In the world you will have tribulation. But take heart; I have overcome the world&rdquo; (John 16:33). The altar set up in the face of fear is the type of faith that worships despite hostile circumstances.</p>",
    "4": "<p><em>Shadow.</em> The Feast of Tabernacles (<em>sukkôt</em>) — the first festival celebrated by the returned community — commemorated the wilderness wandering (Lev 23:42-43). The returning community, dwelling in the vulnerability of incomplete restoration, enacts this festival that celebrates YHWH&rsquo;s provision in the desert. Christ is the fulfillment of Tabernacles: &ldquo;the Word became flesh and tabernacled (<em>eskēnōsen</em>) among us&rdquo; (John 1:14). The divine dwelling in human vulnerability that the festival commemorated became literal in the incarnation.</p>",
    "5": "<p><em>Shadow.</em> The twice-daily <em>ʿōlat hattāmîḏ</em> (continual burnt offering) — morning and evening lambs — the heartbeat of temple ritual. Christ is the fulfillment and end of the <em>tāmîḏ</em>: &ldquo;he has no need, like those high priests, to offer sacrifices daily&hellip; he did this once for all when he offered up himself&rdquo; (Heb 7:27). The daily repetition of the <em>tāmîḏ</em> was a built-in confession of incompleteness; Christ&rsquo;s once-for-all offering is the completion that the daily sacrifice could only announce.</p>",
    "6": "<p><em>Theme.</em> &ldquo;But the foundation of the temple of YHWH had not yet been laid.&rdquo; Sacrifice begins before the building is complete — the altar precedes the temple. Christ&rsquo;s sacrifice on the cross preceded the building of the church: &ldquo;I will build my church&rdquo; (Matt 16:18) — future tense, spoken before the cross. The altar was established before the building so that the building would be grounded in sacrifice rather than sacrifice grounded in the building. The cross is the foundation on which the church is built (1 Cor 3:11).</p>",
    "7": "<p><em>Type.</em> Tyrian and Sidonian craftsmen hired for cedar — the Solomonic pattern replicated. The nations&rsquo; skilled labor contributing to the temple connects the restoration community to its greatest precedent. Christ builds his church with materials gathered from all nations: the Great Commission sends disciples to all nations not only to preach but to incorporate them as living stones in the spiritual temple (1 Pet 2:5; Eph 2:19-22). The Gentile craftsmen of the temple type become the Gentile believers of the church antitype.</p>",
    "8": "<p><em>Type.</em> Second year, second month — the Solomonic timing. The Levites &ldquo;from twenty years old and upward&rdquo; appointed to supervise. Christ appoints his own supervisors for the building of his community: apostles, prophets, evangelists, pastors, and teachers &ldquo;to equip the saints for the work of ministry, for building up the body of Christ&rdquo; (Eph 4:11-12). The Levitical supervisors of the second temple point to the Spirit-gifted ministers who oversee the construction of the living temple.</p>",
    "9": "<p><em>Theme.</em> The Levitical families standing together (<em>yāʿamdû kĕʾeḥāḏ</em>, &ldquo;stood as one&rdquo;) to supervise the builders. The unity of the leadership in the building project prefigures the apostolic unity that characterized the early church: &ldquo;they devoted themselves to the apostles&rsquo; teaching and the fellowship&rdquo; (Acts 2:42). Christ prays for this unity: &ldquo;that they may all be one, just as you, Father, are in me, and I in you&rdquo; (John 17:21). Unified leadership enables unified building.</p>",
    "10": "<p><em>Shadow.</em> The foundation-laying celebrated with priests bearing trumpets and Levitical singers with cymbals — the music of the temple dedication ceremony. The laying of the foundation is the moment when the sacred precinct is established. Christ is the cornerstone that makes the foundation sacred: &ldquo;Behold, I am laying in Zion a stone, a cornerstone chosen and precious&rdquo; (1 Pet 2:6, citing Isa 28:16). When the cornerstone is laid, the trumpet sounds and the community sings — the inauguration of the true temple at Easter is the event that all foundation-laying ceremonies anticipated.</p>",
    "11": "<p><em>Direct.</em> &ldquo;For he is good, for his steadfast love endures forever toward Israel.&rdquo; This refrain — sung at the dedication of Solomon&rsquo;s temple (2 Chr 5:13; 7:3) and now at the second temple&rsquo;s foundation — is the central liturgical affirmation of the covenant. Paul applies the same confession to Christ: &ldquo;all the promises of God find their Yes in him&rdquo; (2 Cor 1:20). &ldquo;His steadfast love endures forever&rdquo; becomes in the NT &ldquo;who shall separate us from the love of Christ?&rdquo; (Rom 8:35) — the love that endures through exile, crucifixion, and death.</p>",
    "12": "<p><em>Theme.</em> The elders who had seen the first temple wept at its lesser replacement. The grief of those who remember former glory is honored in Scripture. Christ speaks to this grief: &ldquo;You mourn now, but your mourning will turn to joy&rdquo; (John 16:20). Hag 2:9 promises the second temple will surpass the first in glory — a promise fulfilled when Christ himself enters it (Luke 2:22-38; John 2:13-22) and declares it is his Father&rsquo;s house. The weeping of the elders at the lesser building is answered by the presence of the greater Solomon in the lesser temple.</p>",
    "13": "<p><em>Theme.</em> The mixed sound — weeping and shouting together, indistinguishable — defines the eschatological tension of the &ldquo;already but not yet.&rdquo; The restoration is real (shout!) but incomplete (weep!). The early church lived in the same tension: already redeemed, not yet glorified; already children of God, not yet revealed as such (Rom 8:18-25). Christ himself wept at Lazarus&rsquo;s tomb (John 11:35) even knowing he would raise him — joy and grief are not mutually exclusive in the inauguration of the kingdom. The indistinguishable sound at Ezra 3:13 is the sonic image of inaugurated eschatology.</p>"
  }
}

def main():
    existing = load_comm('mkt-christ', 'ezra')
    before = sum(len(v) for v in existing.values())
    merge_comm(existing, EZRA_CHRIST_1_3)
    after = sum(len(v) for v in existing.values())
    save_comm('mkt-christ', 'ezra', existing)
    print(f'ezra mkt-christ ch 1-3: wrote {after - before} verses')

if __name__ == '__main__':
    main()
